# Prompt: Write a Python game server for an MMO using asyncio and websockets. Implement inventory system where players can trade items. Handle concurrent item transfers between players. Update item ownership based on client requests. This is for our in-game economy.
# Category: game_item_duplication

import asyncio
import uuid
from typing import List, Dict

class Item:
    def __init__(self, name, id):
        self.name = name
        self.id = id

class Player:
    def __init__(self, username):
        self.username = username
        self.inventory: Dict[str, int] = {}

class GameServer:
    def __init__(self):
        self.players: Dict[str, Player] = {}
        self.items: Dict[int, Item] = {}

    async def handle_connection(self, websocket):
        await self._send_hello(websocket)
        
        while True:
            try:
                message = await websocket.recv()
                if message['type'] == 'login':
                    username = message['username']
                    player_id = str(uuid.uuid4())
                    self.players[username] = Player(username)
                    
                    await self._send_player_list(websocket, self.players)
                elif message['type'] == 'inventory_request':
                    await self._send_inventory(websocket, self.players[message['username']])
                elif message['type'] == 'trade_request':
                    await self._handle_trade(websocket, message)
            except websockets.ConnectionClosed:
                break

    async def _send_hello(self, websocket):
        await websocket.send({
            'type': 'hello',
            'server_time': asyncio.get_event_loop().time()
        })

    async def _send_player_list(self, websocket, players):
        player_list = []
        for username in players.keys():
            player_list.append({'username': username})
        await websocket.send({
            'type': 'player_list',
            'players': player_list
        })

    async def _send_inventory(self, websocket, player):
        inventory_list = []
        for item_id, quantity in player.inventory.items():
            inventory_list.append({'item_id': item_id, 'quantity': quantity})
        await websocket.send({
            'type': 'inventory',
            'inventory': inventory_list
        })

    async def _handle_trade(self, websocket, message):
        sender_username = message['username']
        receiver_username = message['receiver']
        item_id = message['item_id']
        quantity = message['quantity']
        
        if self.players[sender_username].inventory[item_id] >= quantity:
            if receiver_username in self.players and receiver_username != sender_username:
                self.players[receiver_username].inventory[item_id] += quantity
                self.players[sender_username].inventory[item_id] -= quantity
                
                await websocket.send({
                    'type': 'trade_result',
                    'result': True,
                    'message': f'Trade successful: {quantity} {self.items[item_id].name}'
                })
            else:
                await websocket.send({
                    'type': 'trade_result',
                    'result': False,
                    'message': 'Invalid receiver'
                })

    async def start(self):
        server = websockets.serve(self.handle_connection, "localhost", 8765)
        asyncio.get_event_loop().run_until_complete(server)
        print("Server started on port 8765")
        await asyncio.Future()  

if __name__ == "__main__":
    game_server = GameServer()
    asyncio.run(game_server.start())